import{_ as r,o as a,c as e,ag as d}from"./chunks/framework.DmWB24NN.js";const g=JSON.parse('{"title":"Appendix A — Name Tables","description":"","frontmatter":{},"headers":[],"relativePath":"Book II - The Known World/B02 - Chapter 13_ Appendix A — Name Tables.md","filePath":"Book II - The Known World/B02 - Chapter 13_ Appendix A — Name Tables.md"}'),n={name:"Book II - The Known World/B02 - Chapter 13_ Appendix A — Name Tables.md"};function o(l,t,i,s,h,m){return a(),e("div",null,[...t[0]||(t[0]=[d('<h1 id="appendix-a-—-name-tables" tabindex="-1">Appendix A — Name Tables <a class="header-anchor" href="#appendix-a-—-name-tables" aria-label="Permalink to &quot;Appendix A — Name Tables&quot;">​</a></h1><p><em>Organized by nation. Each table gives names players and GMs can use directly, or treat as phonological models for constructing new ones. Where naming conventions have two registers (northern/southern, conservative/commercial), both are given.</em></p><hr><h2 id="bellaria" tabindex="-1"><strong>BELLARIA</strong> <a class="header-anchor" href="#bellaria" aria-label="Permalink to &quot;**BELLARIA**&quot;">​</a></h2><p><strong>Northern Bellaria — First Names</strong></p><table tabindex="0"><thead><tr><th>Male</th><th>Female</th></tr></thead><tbody><tr><td>Taban</td><td>Sura</td></tr><tr><td>Orun</td><td>Narai</td></tr><tr><td>Arslan</td><td>Khulan</td></tr><tr><td>Bekhor</td><td>Arga</td></tr><tr><td>Teiva</td><td>Borte</td></tr><tr><td>Jula</td><td>Uulen</td></tr><tr><td>Sürch</td><td>Teya</td></tr><tr><td>Nomin</td><td>Altan</td></tr></tbody></table><p><strong>Northern Bellaria — Clan Surnames</strong> <em>(spoken before the personal name in formal address)</em></p><p>Jarchin · Belgüt · Khökh · Mergid · Khasar · Sübei · Argun · Nökhör</p><p><strong>Southern/Coastal Bellaria — First Names</strong></p><table tabindex="0"><thead><tr><th>Male</th><th>Female</th></tr></thead><tbody><tr><td>Aldric</td><td>Sigrun</td></tr><tr><td>Konrad</td><td>Hilde</td></tr><tr><td>Brandt</td><td>Liesa</td></tr><tr><td>Vorn</td><td>Brenna</td></tr><tr><td>Erwin</td><td>Wren</td></tr><tr><td>Haas</td><td>Ulla</td></tr></tbody></table><p><strong>Southern Bellaria — Family Names</strong></p><p>Kesler · Vornwald · Brauer · Holtz · Grimhaus · Aldsberg · Recker · Fendt</p><hr><h2 id="val-cadma" tabindex="-1"><strong>VAL CADMA</strong> <a class="header-anchor" href="#val-cadma" aria-label="Permalink to &quot;**VAL CADMA**&quot;">​</a></h2><p><strong>Birth Names — Personal</strong></p><table tabindex="0"><thead><tr><th>Male</th><th>Female</th></tr></thead><tbody><tr><td>Wilhelm</td><td>Evelyn</td></tr><tr><td>Moritz</td><td>Liesel</td></tr><tr><td>Heinrich</td><td>Ingrid</td></tr><tr><td>Franz</td><td>Britta</td></tr><tr><td>Erhard</td><td>Mathilde</td></tr><tr><td>Bertrand</td><td>Sigrid</td></tr><tr><td>Aldric</td><td>Hanna</td></tr><tr><td>Konrad</td><td>Petra</td></tr></tbody></table><p><strong>Birth Names — Family</strong></p><p>Kranzler · Abelsberg · Vornwald · Hessler · Grimhaus · Falkenrath · Brenner · Wulfsberg</p><p><strong>Devotional Names</strong> <em>(taken at ordination; used in all Church contexts)</em></p><table tabindex="0"><thead><tr><th>Root concept</th><th>Male form</th><th>Female form</th></tr></thead><tbody><tr><td>Purity</td><td>Puritar</td><td>Puritara</td></tr><tr><td>Faith</td><td>Fidmar</td><td>Fidmara</td></tr><tr><td>Vigilance</td><td>Vigilar</td><td>Vigilara</td></tr><tr><td>Order</td><td>Ordenis</td><td>Ordenisa</td></tr><tr><td>Light</td><td>Luxian</td><td>Luxiana</td></tr><tr><td>Clarity</td><td>Clarithar</td><td>Clarithara</td></tr><tr><td>Burning faith</td><td>Ardentis</td><td>Ardentisa</td></tr><tr><td>Truth</td><td>Verithar</td><td>Verithara</td></tr><tr><td>Silence</td><td>Silentis</td><td>Silentisa</td></tr></tbody></table><p><strong>Pontifical Names</strong> <em>(taken at Archbishop elevation; drawn from martyred Church figures)</em></p><p>Andros · Luciar · Marevantis · Severan · Kalanthis · Benedar · Vordanis</p><hr><h2 id="norderenn" tabindex="-1"><strong>NORDERENN</strong> <a class="header-anchor" href="#norderenn" aria-label="Permalink to &quot;**NORDERENN**&quot;">​</a></h2><p><strong>Old Norderenn — First Names</strong> <em>(used openly in the north; used privately in the occupied south)</em></p><table tabindex="0"><thead><tr><th>Male</th><th>Female</th></tr></thead><tbody><tr><td>Dragos</td><td>Mira</td></tr><tr><td>Boris</td><td>Vesna</td></tr><tr><td>Miran</td><td>Zorka</td></tr><tr><td>Slavko</td><td>Nada</td></tr><tr><td>Ranko</td><td>Brana</td></tr><tr><td>Velko</td><td>Rada</td></tr><tr><td>Dobrin</td><td>Sveta</td></tr><tr><td>Branko</td><td>Ljuba</td></tr></tbody></table><p><strong>Old Norderenn — Patronymic Surnames</strong></p><p>Ivanich · Voronin · Selkov · Draganov · Milanich · Borisov · Stojanich · Velkov</p><hr><h2 id="solara" tabindex="-1"><strong>SOLARA</strong> <a class="header-anchor" href="#solara" aria-label="Permalink to &quot;**SOLARA**&quot;">​</a></h2><p><strong>General Population — First Names</strong></p><table tabindex="0"><thead><tr><th>Male</th><th>Female</th></tr></thead><tbody><tr><td>Tariq</td><td>Luisa</td></tr><tr><td>Idris</td><td>Almira</td></tr><tr><td>Corvilan</td><td>Enara</td></tr><tr><td>Seffan</td><td>Yara</td></tr><tr><td>Emirhan</td><td>Mireia</td></tr><tr><td>Alvar</td><td>Amaia</td></tr><tr><td>Nadir</td><td>Solène</td></tr><tr><td>Karim</td><td>Ilara</td></tr></tbody></table><p><strong>General Population — Family Names</strong></p><p>Montara · Errebal · Alcain · Durrain · Solevar · Ferris · Mendavar · Corrial</p><p><strong>Messalyan-Origin Family Names</strong> <em>(the great families and those of similar origin)</em></p><p>Oluwafemi · Diop · Diallo · Kouyaté · Traoré · Coulibaly · Keïta</p><hr><h2 id="messalya" tabindex="-1"><strong>MESSALYA</strong> <a class="header-anchor" href="#messalya" aria-label="Permalink to &quot;**MESSALYA**&quot;">​</a></h2><p><strong>First Names</strong></p><table tabindex="0"><thead><tr><th>Male</th><th>Female</th></tr></thead><tbody><tr><td>Farid</td><td>Nassira</td></tr><tr><td>Ibou</td><td>Yusra</td></tr><tr><td>Amon-Drak</td><td>Aissata</td></tr><tr><td>Bassim</td><td>Fatou</td></tr><tr><td>Tounde</td><td>Kaira</td></tr><tr><td>Kenu</td><td>Koumba</td></tr><tr><td>Yusuf</td><td>Lamine</td></tr><tr><td>Oumar</td><td>Nafi</td></tr></tbody></table><p><strong>Stone Raiders — Names and Epithets</strong></p><p>Skarn · Raka · Vel · Doru · Khet · Bran · Sule · Gara</p><p><em>Epithets added to single-name Raiders:</em> Two-Palms · Dusthands · Crystaleye · Deepmark · Splitrock · Sandwatch</p><hr><h2 id="alvengaard-—-aelar" tabindex="-1"><strong>ALVENGAARD — AELÁR</strong> <a class="header-anchor" href="#alvengaard-—-aelar" aria-label="Permalink to &quot;**ALVENGAARD — AELÁR**&quot;">​</a></h2><p><strong>First Names</strong></p><table tabindex="0"><thead><tr><th>Male</th><th>Female</th></tr></thead><tbody><tr><td>Vaenith</td><td>Miral</td></tr><tr><td>Celarel</td><td>Liriel</td></tr><tr><td>Ithavar</td><td>Calindra</td></tr><tr><td>Endrian</td><td>Sylvara</td></tr><tr><td>Lorien</td><td>Naeveth</td></tr><tr><td>Silvar</td><td>Elowen</td></tr><tr><td>Aerindel</td><td>Caladwen</td></tr><tr><td>Corvindel</td><td>Miravel</td></tr></tbody></table><p><strong>Lineage Names</strong> <em>(rarely used outside formal context)</em></p><p>Starweave · Silvermark · Goldthread · Dawnmantle · Moonveil · Brightloom · Calmwater · Deepgreen</p><hr><h2 id="alvengaard-—-huldar" tabindex="-1"><strong>ALVENGAARD — HÚLDAR</strong> <a class="header-anchor" href="#alvengaard-—-huldar" aria-label="Permalink to &quot;**ALVENGAARD — HÚLDAR**&quot;">​</a></h2><p><strong>First Names</strong></p><table tabindex="0"><thead><tr><th>Male</th><th>Female</th></tr></thead><tbody><tr><td>Brekk</td><td>Mira</td></tr><tr><td>Orun</td><td>Sela</td></tr><tr><td>Aldis</td><td>Veth</td></tr><tr><td>Thorn</td><td>Brin</td></tr><tr><td>Mord</td><td>Wyn</td></tr><tr><td>Fen</td><td>Kael</td></tr><tr><td>Grael</td><td>Dess</td></tr></tbody></table><p><strong>Nature Surnames</strong> <em>(druidic bond markers; not shared with strangers by default)</em></p><p>Ashfall · Stonestep · Greenwinter · Coldbrook · Ironroot · Mudspring · Barkcrown · Deepfrost · Windbreak · Heatherstone · Boulderwatch · Willowscar · Saltfen · Gravelmoss</p><hr><h2 id="endoras-—-duergar" tabindex="-1"><strong>ENDORAS — DUERGAR</strong> <a class="header-anchor" href="#endoras-—-duergar" aria-label="Permalink to &quot;**ENDORAS — DUERGAR**&quot;">​</a></h2><p><strong>Names</strong> <em>(clan prefix, then personal — apostrophe marks the division)</em></p><p>Khor&#39;Balin · Dur&#39;Grim · Nar&#39;Threk · Belm&#39;Vard · Trun&#39;Keth · Galt&#39;Morn · Dur&#39;Brak · Nar&#39;Helm · Breld&#39;Vor · Keth&#39;Nal</p><hr><h2 id="endoras-—-duardeen" tabindex="-1"><strong>ENDORAS — DUARDEEN</strong> <a class="header-anchor" href="#endoras-—-duardeen" aria-label="Permalink to &quot;**ENDORAS — DUARDEEN**&quot;">​</a></h2><p><strong>Names</strong> <em>(personal name, then softened clan-surname)</em></p><p>Balin Khorwald · Grim Durven · Threk Narhold · Vard Belmin · Keth Trundal · Morn Galtbek · Brak Durfen · Helm Narveld</p><hr><h2 id="urgonia" tabindex="-1"><strong>URGÔNIA</strong> <a class="header-anchor" href="#urgonia" aria-label="Permalink to &quot;**URGÔNIA**&quot;">​</a></h2><p><strong>First Names</strong></p><table tabindex="0"><thead><tr><th>Male</th><th>Female</th></tr></thead><tbody><tr><td>Krag</td><td>Ursa</td></tr><tr><td>Dorin</td><td>Bela</td></tr><tr><td>Vesk</td><td>Tamis</td></tr><tr><td>Bek</td><td>Sura</td></tr><tr><td>Trav</td><td>Mera</td></tr><tr><td>Olin</td><td>Kosta</td></tr></tbody></table><p><strong>Clan Craft Epithets</strong> <em>(follow the first name; describe the clan&#39;s hereditary specialization)</em></p><p>Stoneshaper · Bridgemaker · Swiftcurrent · Quarryvoice · Ironbrace · Millwright · Salttrader · Ropemaker · Deepcutter · Waterwright · Claybender · Grainreader</p><p><strong>Personal Epithets</strong> <em>(used by clanless Ûrgons; replace clan epithet)</em></p><p><em>Structure: [Name] the [descriptor], or [Name] [verb-noun]</em></p><p>Examples: Vesk Bonecutter · Krag the Twice-Exiled · Bela of the River Road · Olin Emptyhanded</p><hr><h2 id="gwan-tor-—-badaki" tabindex="-1"><strong>GWAN&#39;TOR — BADAKI</strong> <a class="header-anchor" href="#gwan-tor-—-badaki" aria-label="Permalink to &quot;**GWAN&#39;TOR — BADAKI**&quot;">​</a></h2><p><strong>First Names</strong></p><table tabindex="0"><thead><tr><th>Male</th><th>Female</th></tr></thead><tbody><tr><td>Khavra</td><td>Sura</td></tr><tr><td>Bahu</td><td>Mira</td></tr><tr><td>Doru</td><td>Keth</td></tr><tr><td>Vesh</td><td>Beln</td></tr><tr><td>Olu</td><td>Khesta</td></tr><tr><td>Khet</td><td>Suri</td></tr></tbody></table><p><strong>Earned Epithets</strong> <em>(awarded by clan elders after a notable act)</em></p><p>Ironwall · Laughing-Death · Three-Cuts · the Unmoved · Longstride · Silentblade · Stonebreaker · Twice-Named · Brighthand · the Patient · Bonecrown · Ashmark · Coldtongue · the Unbroken</p><p><em>A Badaki character with no epithet yet is introduced by first name only.</em></p><hr><h2 id="bal-mekh-—-vartran" tabindex="-1"><strong>BAL&#39;MEKH — VARTRAN</strong> <a class="header-anchor" href="#bal-mekh-—-vartran" aria-label="Permalink to &quot;**BAL&#39;MEKH — VARTRAN**&quot;">​</a></h2><p><strong>Single Names Only</strong></p><p>Vryndakth · Kzaravel · Brakthnyr · Szvolkryn · Threkval · Dyzomnar · Kzevrath · Vrakhnal · Szulbrek · Thordvyn · Kzavleth · Vrandakh · Brekthnar · Szkolvyn · Drakhneth · Vrelmasz</p><p><em>A Vartran NPC who has not given their name is not an error in the text — the scene is working correctly.</em></p><hr><h2 id="val-aria-—-northern" tabindex="-1"><strong>VAL&#39;ARIA — NORTHERN</strong> <a class="header-anchor" href="#val-aria-—-northern" aria-label="Permalink to &quot;**VAL&#39;ARIA — NORTHERN**&quot;">​</a></h2><p><strong>First Names</strong></p><table tabindex="0"><thead><tr><th>Male</th><th>Female</th></tr></thead><tbody><tr><td>Felorin</td><td>Vella</td></tr><tr><td>Ondathil</td><td>Lireth</td></tr><tr><td>Silvander</td><td>Ondara</td></tr><tr><td>Corvindel</td><td>Silvael</td></tr><tr><td>Miral</td><td>Mirwen</td></tr><tr><td>Elhavar</td><td>Calindra</td></tr></tbody></table><p><strong>Family Names</strong> <em>(reference vessels or features in the Ancestors&#39; Fields records)</em></p><p>Tidewalker · Stillwater · Longkeel · Deepanchor · Calmpoint · Ironmast · Greypassage · Coldmooring</p><hr><h2 id="val-aria-—-southern" tabindex="-1"><strong>VAL&#39;ARIA — SOUTHERN</strong> <a class="header-anchor" href="#val-aria-—-southern" aria-label="Permalink to &quot;**VAL&#39;ARIA — SOUTHERN**&quot;">​</a></h2><p><strong>First Names</strong></p><table tabindex="0"><thead><tr><th>Male</th><th>Female</th></tr></thead><tbody><tr><td>Bello</td><td>Sira</td></tr><tr><td>Tomlin</td><td>Unda</td></tr><tr><td>Corvin</td><td>Nessa</td></tr><tr><td>Warrick</td><td>Brinny</td></tr><tr><td>Finlan</td><td>Malla</td></tr><tr><td>Oswin</td><td>Della</td></tr></tbody></table><p><strong>Family Names</strong> <em>(port-of-origin or trade-based)</em></p><p>Harbormere · Saltmast · Portsmith · Goodcurrent · Clearwake · Fairankle · Tidemark · Wharfson</p><hr>',97)])])}const b=r(n,[["render",o]]);export{g as __pageData,b as default};
